27	  // Redis - Optional with default
28	  REDIS_URL: z.string().default("redis://localhost:6379"),
29	
30	  // Server configuration
31	  PORT: z.coerce.number().default(3000),
32	  NODE_ENV: z.enum(["development", "production", "test"]).default("development"),
33	  LOG_LEVEL: z.enum(["trace", "debug", "info", "warn", "error", "fatal"]).default("info"),
34	
35	  // Feature flags
36	  ENABLE_WORKER_QUEUE: z.string().default("false"),
37	  NEXT_PUBLIC_DEMO_MODE: z.string().optional(),
38	
39	  // Vercel (optional, for deployment)
40	  VERCEL_URL: z.string().optional(),
41	  
42	  // Worker configuration
43	  WORKER_CONCURRENCY: z.coerce.number().default(5),
44	});
45	
46	// Client-side safe schema (only public env vars)
47	const clientEnvSchema = z.object({
48	  NEXT_PUBLIC_DEMO_MODE: z.string().optional(),
49	});
50	
51	type ServerEnv = z.infer<typeof envSchema>;
52	type ClientEnv = z.infer<typeof clientEnvSchema>;
53	
54	/**
55	 * Validated server environment variables
56	 * Will throw and prevent app startup if required vars are missing
57	 * 
58	 * Note: We use console.error here instead of the pino logger because
59	 * the logger itself depends on env vars and may not be initialized yet.
60	 */
61	function validateServerEnv(): ServerEnv {
62	  const result = envSchema.safeParse(process.env);
63	
64	  if (!result.success) {
65	    console.error("\n[env] FATAL: Missing or invalid environment variables\n");
66	    
67	    const errors = result.error.flatten().fieldErrors;
68	    for (const [key, messages] of Object.entries(errors)) {
69	      console.error(`  ${key}:`);
70	      messages?.forEach((msg) => console.error(`    - ${msg}`));
71	    }
72	
73	    console.error("\nCreate a .env file with the required variables.");
74	    console.error("See .env.example for reference.\n");
75	    
76	    process.exit(1);
77	  }
78	
79	  return result.data;
80	}
81	
82	/**
83	 * Validated client environment variables (safe for browser)
84	 */
85	function validateClientEnv(): ClientEnv {
86	  return clientEnvSchema.parse({
87	    NEXT_PUBLIC_DEMO_MODE: process.env.NEXT_PUBLIC_DEMO_MODE,
88	  });
89	}
90	
